public class Main {
    public static void main(String[] args) throws Exception {
        java.io.BufferedReader br = new java.io.BufferedReader(new java.io.InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        String line;
        // Read number of test cases, skipping empty lines
        line = br.readLine();
        while (line != null && line.trim().isEmpty()) {
            line = br.readLine();
        }
        int T = Integer.parseInt(line.trim());
        for (int tc = 0; tc < T; tc++) {
            // Read N, skipping empty lines
            do {
                line = br.readLine();
            } while (line != null && line.trim().isEmpty());
            int N = Integer.parseInt(line.trim());
            int count = 0;
            long first = 0, third = 0;
            while (count < N) {
                line = br.readLine();
                if (line == null) break;
                java.util.StringTokenizer st = new java.util.StringTokenizer(line);
                while (st.hasMoreTokens() && count < N) {
                    int val = Integer.parseInt(st.nextToken());
                    if (count == 0) first = val;
                    if (count == 2) third = val;
                    count++;
                }
            }
            sb.append(first * third);
            if (tc != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

